import sys

class Solution:
    def unboundedKnapsack(self, W: int, weights: list[int], values: list[int]) -> int:
        dp = [0] * (W + 1)
        for w in range(1, W + 1):
            for i in range(len(weights)):
                if weights[i] <= w:
                    dp[w] = max(dp[w], dp[w - weights[i]] + values[i])
        return dp[W]

