#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int unboundedKnapsack(int W, vector<int>& weights, vector<int>& values) {
        vector<int> dp(W + 1);
        for (int w = 1; w <= W; w++) {
            for (int i = 0; i < weights.size(); i++) {
                if (weights[i] <= w) {
                    dp[w] = max(dp[w], dp[w - weights[i]] + values[i]);
                }
            }
        }
        return dp[W];
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n, W;
    if (!(cin >> n >> W)) return 0;
    vector<int> weights(n), values(n);
    for (int i = 0; i < n; i++) cin >> weights[i] >> values[i];
    Solution sol;
    int ans = sol.unboundedKnapsack(W, weights, values);
    cout << ans << "\n";
    return 0;
}
